import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from '../api/axios';

const PlanPage = () => {
    const [tasks, setTasks] = useState([]);
    const navigate = useNavigate();

    useEffect(() => {
        const fetchTasks = async () => {
            try {
                const res = await axios.get('/tasks');
                setTasks(res.data);
            } catch (err) { console.error(err); }
        };
        fetchTasks();
    }, []);

    const completed = tasks.filter(t => t.status === 'completed').length;
    const progress = tasks.length > 0 ? (completed / tasks.length) * 100 : 0;

    return (
        <div style={{ padding: '30px' }}>
            <h2>My Progress</h2>
            <div style={{ width: '100%', background: '#eee', height: '15px', borderRadius: '10px', marginBottom: '20px' }}>
                <div style={{ width: `${progress}%`, background: '#27ae60', height: '100%', borderRadius: '10px', transition: '0.5s' }} />
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' }}>
                {tasks.map((task, index) => (
                    <div key={task._id} onClick={() => task.status !== 'completed' && navigate(`/study-room/${task._id}`)}
                        style={{ padding: '20px', border: '1px solid #ddd', borderRadius: '8px', background: task.status === 'completed' ? '#d4edda' : '#fff', cursor: 'pointer' }}>
                        <strong>Day {index + 1}</strong>
                        <p>{task.title}</p>
                        <span>{task.status === 'completed' ? '✅ Done' : '⏳ Pending'}</span>
                    </div>
                ))}
            </div>
        </div>
    );
};

export default PlanPage;
